from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/api/profile', methods=['POST'])
def update_profile():
    data = request.json
    new_email = data.get('email')
    new_password = data.get('password')
    two_factor_enabled = data.get('twoFactorEnabled')

    # Here you would typically add validation and update logic
    # For example, updating the user's profile in a database

    # Simulate successful update
    session['email'] = new_email if new_email else session.get('email')
    session['password'] = new_password if new_password else session.get('password')
    session['two_factor_enabled'] = two_factor_enabled

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)